#include <bits/stdc++.h>
using namespace std;
const long long mod=1e17;
long long n,f[1000006],sum;
int main(){
    scanf("%lld",&n);
    for(int i=1;i<=n;i++)
        if(i<3)
            f[i]=i,sum+=f[i];
        else
            f[i]=sum*2+2+mod*2-f[i-1]-f[i-2],f[i]%=mod,sum+=f[i],sum%=mod;
    printf("%lld",f[n]%10000);
    return 0;
}
